// Declare image file modules as strings so they work with <img src={...}>
// Next.js by default returns StaticImageData for image imports, but since
// we're using standard <img> tags (not next/image), we need string URLs.
declare module '*.webp' {
  const content: string;
  export default content;
}

declare module '*.png' {
  const content: string;
  export default content;
}

declare module '*.jpg' {
  const content: string;
  export default content;
}

declare module '*.jpeg' {
  const content: string;
  export default content;
}

declare module '*.gif' {
  const content: string;
  export default content;
}

declare module '*.svg' {
  const content: string;
  export default content;
}
